import{supabase,agents as agentsApi}from '../portal/supabase.js';class AgentEventBus{constructor(){this.listeners=new Map();}on(event,callback){if(!this.listeners.has(event)){this.listeners.set(event,[]);}this.listeners.get(event).push(callback);}emit(event,data){if(this.listeners.has(event)){this.listeners.get(event).forEach(callback=>callback(data));}}}const agentBus=new AgentEventBus();class Agent{constructor(config){this.name=config.name;this.role=config.role||'worker';this.capabilities=config.capabilities||[];this.state='idle';}log(message,type='info'){agentBus.emit('agent:log',{agent: this.name,type,message,timestamp: new Date().toISOString()});}async processTask(task){this.state='working';agentBus.emit('agent:state-change',{agent: this.name,newState: 'working'});try{this.log(`Processing task: ${task.title}`,'working');const result=await this.execute(task);this.state='completed';agentBus.emit('agent:state-change',{agent: this.name,newState: 'completed'});return result;}catch(error){this.state='error';this.log(`Error: ${error.message}`,'error');agentBus.emit('agent:state-change',{agent: this.name,newState: 'error'});throw error;}finally{setTimeout(()=>{this.state='idle';agentBus.emit('agent:state-change',{agent: this.name,newState: 'idle'});},3000);}}async execute(task){await new Promise(r=>setTimeout(r,2000));return{message: 'Task completed'};}}class EditorAgent extends Agent{constructor(){super({name: 'Editor',capabilities: ['Content Creation','Copywriting','SEO']});}async execute(task){this.log('Drafting content with AI...','working');const{data,error}=await supabase.functions.invoke('generate-content',{body:{taskId: task.id,prompt: task.description,context:{agent: 'Editor'}}});if(error)throw error;this.log('Content generated and saved.','success');return data;}}class ScoutAgent extends Agent{constructor(){super({name: 'Scout',capabilities: ['Market Research','Competitor Analysis']});}async execute(task){this.log('Searching for information...','working');await new Promise(r=>setTimeout(r,2000));this.log('Research completed.','success');return{success: true};}}class DirectorAgent extends Agent{constructor(){super({name: 'Director',capabilities: ['Video Scripting','Storyboard']});}async execute(task){this.log('Planning video content...','working');await new Promise(r=>setTimeout(r,2000));this.log('Video plan created.','success');return{success: true};}}class AgentSystem{constructor(){this.agents=new Map();this.initialized=false;this.pollingInterval=null;this.processedTaskIds=new Set();}async initialize(){if(this.initialized)return;this.agents.set('Editor',new EditorAgent());this.agents.set('Scout',new ScoutAgent());this.agents.set('Director',new DirectorAgent());this.initialized=true;agentBus.emit('system:initialized',{timestamp: new Date().toISOString(),agents: Array.from(this.agents.keys())});this.startPolling();return this;}async submitTask(description){if(!this.initialized)await this.initialize();try{const{data: task,error: createError}=await agentsApi.createTask({title: description.substring(0,50)+(description.length>50 ? '...' : ''),description: description,status: 'pending'});if(createError)throw createError;agentBus.emit('agent:log',{agent: 'System',type: 'info',message: `Task submitted: ${task.title}`,timestamp: new Date().toISOString()});const{data: result,error: funcError}=await supabase.functions.invoke('agent-supervisor',{body:{taskId: task.id,action: 'delegate'}});if(funcError)throw funcError;agentBus.emit('agent:log',{agent: 'Supervisor',type: 'routing',message: result.message,timestamp: new Date().toISOString()});agentBus.emit('task:routed',{targetAgent: result.assignedTo});return task;}catch(error){agentBus.emit('agent:log',{agent: 'System',type: 'error',message: `Error: ${error.message}`,timestamp: new Date().toISOString()});throw error;}}startPolling(){if(this.pollingInterval)clearInterval(this.pollingInterval);this.pollingInterval=setInterval(async()=>{const{data: tasks}=await supabase .from('agent_tasks').select('*,agent:agents(name)').eq('status','in_progress').order('updated_at',{ascending: true});if(tasks){for(const task of tasks){if(this.processedTaskIds.has(task.id))continue;const agentName=task.agent?.name;const agent=this.agents.get(agentName);if(agent&&agent.state==='idle'){this.processedTaskIds.add(task.id);agent.processTask(task).catch(()=>{this.processedTaskIds.delete(task.id);});}}}},3000);}getAllAgents(){return Array.from(this.agents.values()).map(agent=>({name: agent.name,state: agent.state,capabilities: agent.capabilities,purpose: agent.name+' Agent'}));}getSystemStatus(){const subAgents={};this.agents.forEach((agent,name)=>{subAgents[name]={state: agent.state};});return{initialized: this.initialized,subAgents};}}const mekongAgents=new AgentSystem();if(typeof window!=='undefined'){window.mekongAgents=mekongAgents;window.agentBus=agentBus;}export{AgentSystem,agentBus,mekongAgents};